import 'dart:typed_data'; import 'package:pdf/pdf.dart'; import 'package:pdf/widgets.dart' as pw; class InvoicePdfService { static const double markup = 1.05; static Future<Uint8List> generateInvoice({required String clientName, required String packageName, required double packageBasePrice, required List<Map<String, dynamic>> extras}) async { final pdf = pw.Document(); pdf.addPage(pw.Page(pageFormat: PdfPageFormat.a4, build: (pw.Context context) { double totalAmount = (packageBasePrice * markup); return pw.Column(crossAxisAlignment: pw.CrossAxisAlignment.start, children: [pw.Container(color: PdfColors.brown800, padding: const pw.EdgeInsets.all(16), child: pw.Row(mainAxisAlignment: pw.MainAxisAlignment.spaceBetween, children: [pw.Text('JAGSPOOR HUNTING INVOICE', style: pw.TextStyle(color: PdfColors.white, fontSize: 18, fontWeight: pw.FontWeight.bold)), pw.Text('Client: $clientName', style: pw.TextStyle(color: PdfColors.white, fontWeight: pw.FontWeight.bold))])), pw.SizedBox(height: 24), pw.Text('1. Included Base Packages', style: pw.TextStyle(fontSize: 14, fontWeight: pw.FontWeight.bold)), pw.SizedBox(height: 8), pw.TableHelper.fromTextArray(headers: ['Package Description', 'Total Price (ZAR) '], headerStyle: pw.TextStyle(fontWeight: pw.FontWeight.bold), data: [[packageName, 'R ${totalAmount.toStringAsFixed(2)}']]), pw.SizedBox(height: 24), pw.Text('2. Field Extras & Butchery Items', style: pw.TextStyle(fontSize: 14, fontWeight: pw.FontWeight.bold)), pw.SizedBox(height: 8), pw.TableHelper.fromTextArray(headers: ['Item Description', 'Qty / Days', 'Unit Price', 'Subtotal (ZAR) '], headerStyle: pw.TextStyle(fontWeight: pw.FontWeight.bold), data: extras.map((item) { final double rawPrice = (item['price'] is num) ? (item['price'] as num).toDouble() : double.tryParse(item['price'].toString()) ?? 0.0; final double hunterPrice = rawPrice * markup; final int qty = (item['multiplier'] is int) ? (item['multiplier'] as int) : int.tryParse(item['multiplier'].toString()) ?? 1; final double subtotal = hunterPrice * qty; totalAmount += subtotal; return [item['name'] ?? 'Extra Item', qty.toString(), 'R ${hunterPrice.toStringAsFixed(2)}', 'R ${subtotal.toStringAsFixed(2)}']; }).toList()), pw.SizedBox(height: 30), pw.Divider(color: PdfColors.grey500), pw.SizedBox(height: 10), pw.Align(alignment: pw.Alignment.centerRight, child: pw.Text('TOTAL AMOUNT DUE: R ${totalAmount.toStringAsFixed(2)}', style: pw.TextStyle(fontSize: 18, fontWeight: pw.FontWeight.bold, color: PdfColors.brown900)))]); })); return pdf.save(); } }
